// TermsIQ URL Validity Agent — n8n Code Node
// Replicates url_agent.py logic in JavaScript
// Reads annotation_base.json, checks all URLs, returns structured results

const ANNOTATION_PATH = 'C:/Users/dilia/OneDrive/IronHack/Projects/final-project-Dilia-Navarro/poc/Annotations/annotation_base.json';
const JS_RENDER_THRESHOLD = 5000;
const REQUEST_TIMEOUT_MS  = 15000;
const SKIP_PREFIXES = ['local://', 'session://', 'file://'];

const STATUS = {
  OK:          'OK',
  NOT_FOUND:   '404',
  BLOCKED:     'BLOCKED',
  JS_RENDERED: 'JS_RENDERED',
  REDIRECT:    'REDIRECT',
  TIMEOUT:     'TIMEOUT',
  ERROR:       'ERROR',
  SKIP:        'SKIP',
};

const ACTION_STATUSES = new Set([
  STATUS.NOT_FOUND, STATUS.JS_RENDERED,
  STATUS.REDIRECT,  STATUS.TIMEOUT, STATUS.ERROR
]);

// Load annotation base
const fs  = require('fs');
const url = require('url');

let annotationData;
try {
  const raw = fs.readFileSync(ANNOTATION_PATH, 'utf8');
  annotationData = JSON.parse(raw);
} catch (e) {
  return [{ json: {
    error: `Could not read annotation_base.json: ${e.message}`,
    issuesCount: 0, issues: [], allResults: [],
    runTimestamp: new Date().toISOString(), exitCode: 0
  }}];
}

// Check a single URL
function checkUrl(rawUrl) {
  return new Promise((resolve) => {
    if (SKIP_PREFIXES.some(p => rawUrl.startsWith(p))) {
      return resolve({ status: STATUS.SKIP, note: 'Local or session-authenticated' });
    }
    const parsed  = url.parse(rawUrl);
    const lib     = rawUrl.startsWith('https') ? require('https') : require('http');
    const options = {
      hostname: parsed.hostname,
      port:     parsed.port || (rawUrl.startsWith('https') ? 443 : 80),
      path:     parsed.path,
      method:   'GET',
      headers:  { 'User-Agent': 'TermsIQ-URLAgent/1.0' },
      timeout:  REQUEST_TIMEOUT_MS,
    };
    const req = lib.request(options, (res) => {
      const code        = res.statusCode;
      const location    = res.headers['location'];
      const contentType = res.headers['content-type'] || '';
      let body = '';
      res.on('data', chunk => { body += chunk; });
      res.on('end', () => {
        if (code === 404) return resolve({ status: STATUS.NOT_FOUND, code, note: 'HTTP 404 — URL no longer exists' });
        if (code === 403) return resolve({ status: STATUS.BLOCKED,   code, note: 'HTTP 403 — server blocks bots, URL likely valid' });
        if (code >= 300 && code < 400 && location) return resolve({ status: STATUS.REDIRECT, code, redirectUrl: location, note: `Redirected to: ${location}` });
        if (code >= 400) return resolve({ status: STATUS.ERROR, code, note: `HTTP ${code}` });
        if (contentType.includes('text/html')) {
          const textOnly = body.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
          if (textOnly.length < JS_RENDER_THRESHOLD) return resolve({ status: STATUS.JS_RENDERED, code, note: `Only ${textOnly.length} chars — likely JS-rendered` });
        }
        resolve({ status: STATUS.OK, code, note: `${body.length.toLocaleString()} bytes | ${contentType.split(';')[0].trim()}` });
      });
    });
    req.on('timeout', () => { req.destroy(); resolve({ status: STATUS.TIMEOUT, note: `Timed out after ${REQUEST_TIMEOUT_MS/1000}s` }); });
    req.on('error',   e  => resolve({ status: STATUS.ERROR, note: `Error: ${e.message}` }));
    req.end();
  });
}

// Extract all URLs from a record
function collectUrls(record) {
  const urls = [];
  const src  = record.sources || {};
  if (src.primary)             urls.push({ path: 'sources.primary',             url: src.primary.url,             fields: [] });
  if (src.primary_pdf_fallback) urls.push({ path: 'sources.primary_pdf_fallback', url: src.primary_pdf_fallback.url, fields: [] });
  (src.secondary || []).forEach((s, i) => urls.push({ path: `sources.secondary[${i}]`, url: s.url, fields: s.fields_covered || [] }));
  return urls;
}

// Run checks
const runTimestamp = new Date().toISOString();
const issues     = [];
const allResults = [];

for (const record of (annotationData.records || [])) {
  for (const urlInfo of collectUrls(record)) {
    await new Promise(r => setTimeout(r, 1000)); // polite delay
    const result = await checkUrl(urlInfo.url);
    const entry  = {
      record:   record.id,
      supplier: record.supplier,
      country:  record.country,
      path:     urlInfo.path,
      url:      urlInfo.url,
      status:   result.status,
      code:     result.code || null,
      note:     result.note,
      redirectUrl:   result.redirectUrl || null,
      fieldsCovered: urlInfo.fields,
    };
    allResults.push(entry);
    if (ACTION_STATUSES.has(result.status)) issues.push(entry);
  }
}

const totalChecked = allResults.filter(r => r.status !== STATUS.SKIP).length;
const totalOk      = allResults.filter(r => r.status === STATUS.OK).length;
const totalBlocked = allResults.filter(r => r.status === STATUS.BLOCKED).length;
const totalSkipped = allResults.filter(r => r.status === STATUS.SKIP).length;

return [{ json: {
  runTimestamp,
  runDate:      runTimestamp.split('T')[0],
  totalChecked, totalOk, totalBlocked, totalSkipped,
  issuesCount:  issues.length,
  issues,
  allResults,
  exitCode:     issues.length > 0 ? 1 : 0,
}}];

// Build HTML email from agent results
const data   = $input.first().json;
const issues = data.issues || [];

const statusColors = {
  '404':         '#dc2626',
  'JS_RENDERED': '#d97706',
  'REDIRECT':    '#2563eb',
  'TIMEOUT':     '#7c3aed',
  'ERROR':       '#dc2626',
};
const actionGuide = {
  '404':         'URL deleted. Find replacement and update annotation_base.json.',
  'JS_RENDERED': 'Page now JS-rendered. Add or update PDF fallback URL.',
  'REDIRECT':    'URL moved. Update annotation_base.json with new URL.',
  'TIMEOUT':     'Server slow. Retry manually before taking action.',
  'ERROR':       'Unexpected error. Check URL manually.',
};

let rows = '';
for (const issue of issues) {
  const color  = statusColors[issue.status] || '#374151';
  const action = actionGuide[issue.status]  || 'Check manually.';
  rows += `<tr>
    <td style="padding:8px;border:1px solid #e5e7eb;font-weight:bold">${issue.record}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;color:${color};font-weight:bold">${issue.status}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px;word-break:break-all">${issue.url}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px">${issue.note}</td>
    <td style="padding:8px;border:1px solid #e5e7eb;font-size:12px">${action}</td>
  </tr>`;
}

const html = `<html><body style="font-family:Arial,sans-serif;color:#111827;max-width:900px;margin:0 auto">
<h2 style="color:#dc2626">⚠ TermsIQ URL Agent — Action Required</h2>
<p><strong>${issues.length} issue(s) detected</strong> on ${data.runDate}.</p>
<p>Summary: ${data.totalChecked} checked | ${data.totalOk} OK | ${data.totalBlocked} blocked (403) | ${data.totalSkipped} skipped</p>
<table style="border-collapse:collapse;width:100%;font-size:13px">
<thead><tr style="background:#f3f4f6">
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Record</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Status</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">URL</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Note</th>
  <th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Action</th>
</tr></thead>
<tbody>${rows}</tbody>
</table>
<h3>Next steps</h3>
<ol>
  <li>Open <code>poc/Annotations/annotation_base.json</code></li>
  <li>Find the affected record and update the URL</li>
  <li>Re-run: <code>python poc/Annotations/url_agent.py --annotation poc/Annotations/annotation_base.json</code></li>
</ol>
<p style="color:#6b7280;font-size:12px">— TermsIQ URL Agent | ${data.runTimestamp}</p>
</body></html>`;

return [{ json: { ...data, emailHtml: html,
  emailSubject: `⚠ TermsIQ URL Agent — ${issues.length} issue(s) — ${data.runDate}` } }];

const data = $input.first().json;
console.log(`[TermsIQ URL Agent] ${data.runDate} — All OK. Checked: ${data.totalChecked}, OK: ${data.totalOk}, Blocked: ${data.totalBlocked}, Skipped: ${data.totalSkipped}`);
return [{ json: { status: 'ALL_OK', ...data } }];
